  int current = seed;
  List<int> allIndexes = List.generate(arr.length, (index) => index);
  _fisherYatesShuffle(allIndexes, current);
  List<int> biggerIndexes = allIndexes.sublist(0, n);
  current = seed;
  Set<int> smallerIndexes = Set();
  int maxAttempts = 1000;
  int attempts = 0;

  while (smallerIndexes.length < min(n - 1, arr.length) && attempts < maxAttempts) {
    current = _parkMillerRNG(current);
    int index = current % arr.length;
    if (biggerIndexes.contains(index)) {
      continue;
    }
    smallerIndexes.add(index);
    attempts++;
  }

  List<int> randomInts = [];
  for (int index in biggerIndexes) {
    randomInts.add(arr[index]);
  }
  for (int index in smallerIndexes) {
    randomInts.add(arr[index]);
  }
  _fisherYatesShuffle(randomInts, current);
  return randomInts;
