int _parkMillerRNG(int seed) {
  return (seed * 16807) % 2147483647;
}

void _fisherYatesShuffle(List<int> list, int seed) {
  for (int i = list.length - 1; i > 0; i--) {
    int j = _parkMillerRNG(seed) % (i + 1);
    int temp = list[i];
    list[i] = list[j];
    list[j] = temp;
  }
}
